import { useRouter } from 'next/router';
import { useEffect, useState } from 'react';

export default function ProductDetail() {
    const router = useRouter();
    const { id } = router.query;
    const [product, setProduct] = useState(null);

    useEffect(() => {
        if (id) {
            fetch(`/api/products/${id}`)
                .then((res) => res.json())
                .then((data) => setProduct(data));
        }
    }, [id]);

    if (!product) return <div className="text-center p-10">Memuat produk...</div>;

    return (
        <div className="max-w-4xl mx-auto p-8 font-sans">
            <button onClick={() => router.back()} className="mb-4 text-blue-500">← Kembali</button>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                {/* FOTO BESAR */}
                <div className="bg-gray-100 rounded-xl overflow-hidden aspect-square flex items-center justify-center">
                    <img src={product.image || 'https://via.placeholder.com/400'} alt={product.name} className="w-full h-full object-cover" />
                </div>

                {/* DETAIL PRODUK */}
                <div>
                    <span className="bg-blue-100 text-blue-800 text-xs font-bold px-2.5 py-0.5 rounded">{product.badge}</span>
                    <h1 className="text-3xl font-bold mt-2">{product.name}</h1>
                    <p className="text-2xl text-gray-600 mt-2">Rp {product.price?.toLocaleString()}</p>

                    <div className="mt-6">
                        <h3 className="font-bold">Deskripsi Lengkap:</h3>
                        <p className="text-gray-600 mt-2">{product.description || "Produk berkualitas tinggi untuk gaya hidup Gen-Z kamu."}</p>
                    </div>

                    <p className="mt-4 text-sm text-gray-500">Stok tersedia: <span className="font-bold text-black">{product.stock}</span></p>

                    {/* TOMBOL BELI */}
                    <button className="w-full bg-black text-white py-4 rounded-xl mt-8 font-bold hover:bg-gray-800 transition">
                        Beli Sekarang
                    </button>
                </div>
            </div>
        </div>
    );
}